export const PaymentMethodSection = ({ actionPage, donorProfile, isEmbedded }: Props) => {
  const { t } = useTranslation('actionPages');
  const { setValue, trigger } = useFormContext();
  const { isOpen, onClose, onToggle } = useDisclosure();
  const { paymentMethods } = useDonorPaymentMethods({
    actionPage,
    performRedirect: false,
    retry: false,
  });

  const [selectedPaymentMethod, setSelectedPaymentMethod] =
    useState<UserPaymentMethodResponse | null>(null);

  const isDonation = actionPage.pageType !== 'lead';

  const {
    businessDirectDebitEnabled,
    creditCardEnabled,
    paypalEnabled,
    personalDirectDebitEnabled,
  } = actionPage.paymentConfiguration || {};

  const selectPaymentMethod = useCallback(
    (method: UserPaymentMethodResponse | null) => {
      setSelectedPaymentMethod(method);

      if (method) {
        setValue('hasValidDonorPaymentMethod', true);
        setValue('paymentMethodId', method.id);
        setValue('type', method.type);
        setValue('cardType', method.cardType);
        setValue('cardZip', method.postalCode || donorProfile?.postalCode);
      } else {
        setValue('hasValidDonorPaymentMethod', false);
        setValue('paymentMethodId', null);
        setValue(
          'type',
          creditCardEnabled
            ? 'credit_card'
            : businessDirectDebitEnabled || personalDirectDebitEnabled
              ? 'plaid_bank_account'
              : !isEmbedded && paypalEnabled
                ? 'paypal'
                : undefined
        );
        setValue('cardType', null);
      }

      // trigger payment method fields from PaymentMethodForm.tsx
      trigger('accountHolderType');
      trigger('accountNumber');
      trigger('accountType');
      trigger('cardZip');
      trigger('checkNumber');
      trigger('confirmNumber');
      trigger('cvv');
      trigger('expDate');
      trigger('plaidBankAccountId');
      trigger('routingNumber');
      trigger('type');
      trigger('vaultToken');
      trigger('vaultToken');

      onClose();
    },
    [
      businessDirectDebitEnabled,
      creditCardEnabled,
      donorProfile?.postalCode,
      isEmbedded,
      onClose,
      paypalEnabled,
      personalDirectDebitEnabled,
      setValue,
      trigger,
    ]
  );

  useEffect(() => {
    if (!paymentMethods) {
      setValue('hasValidDonorPaymentMethod', false);
      return;
    }

    setValue('hasValidDonorPaymentMethod', paymentMethods.length > 0);
    selectPaymentMethod(paymentMethods[0]);
  }, [paymentMethods, selectPaymentMethod, setValue]);

  if (!isDonation || !paymentMethods?.length) {
    return null;
  }

  return (
    <div className="flex flex-col gap-4">
      <Divider borderColor="border-neutral-200" />
      <div className="flex grow flex-col gap-3">
        <Button className="flex cursor-pointer pr-4" onClick={onToggle} variant="unstyled">
          {selectedPaymentMethod ? (
            <PaymentMethodRow
              as="div"
              key={selectedPaymentMethod.id}
              paymentMethod={selectedPaymentMethod}
            />
          ) : (
            <Label className="ml-16 !font-normal">{t('chooseExistingPaymentMethod')}</Label>
          )}
          <ChevronDownIcon
            className={clsx('ease ml-auto w-[16px] transition-all duration-200', {
